// Fetch scenes with has_video=true for this topic. Resume support: only pending video_status.
const body = $('Webhook Trigger').item.json.body;
const topicId = body.topic_id;
const projectId = body.project_id;

if (!topicId) {
  return [{ json: { success: false, error: 'topic_id is required', scenes: [], skip: true } }];
}

const sbUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Fetch video scenes that still need I2V generation
const scenesUrl = `${sbUrl}/rest/v1/scenes?topic_id=eq.${topicId}&has_video=eq.true&video_status=eq.pending&image_status=eq.uploaded&order=scene_number.asc&select=id,topic_id,project_id,scene_number,scene_id,image_prompt,image_url,video_placement_start_ms,video_placement_end_ms,audio_duration_ms,zoom_direction,color_mood,composition_prefix`;

const resp = await fetch(scenesUrl, { method: 'GET', headers: sbHeaders });
if (!resp.ok) {
  const errText = await resp.text();
  return [{ json: { success: false, error: `Failed to fetch scenes: HTTP ${resp.status}: ${errText.slice(0, 300)}`, scenes: [], skip: true } }];
}

const scenes = await resp.json();

if (!Array.isArray(scenes) || scenes.length === 0) {
  // No video scenes to process — proceed directly to ken_burns
  try {
    await fetch(`${sbUrl}/rest/v1/topics?id=eq.${topicId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ pipeline_stage: 'ken_burns' })
    });
  } catch (_) { }
  return [{ json: { success: true, topic_id: topicId, project_id: projectId, scenes: [], skip: true, message: 'No pending video scenes — advancing to ken_burns' } }];
}

// Log start
try {
  await fetch(`${sbUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId || scenes[0].project_id,
      topic_id: topicId,
      stage: 'i2v_hybrid',
      scene_number: null,
      action: 'started',
      status: 'running',
      duration_ms: 0,
      cost_usd: 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{ json: {
  success: true,
  topic_id: topicId,
  project_id: projectId || scenes[0].project_id,
  scenes: scenes,
  total_video_scenes: scenes.length,
  skip: false
} }];

