// 4. PATCH scene with video_clip_url + video_status

const data = $input.first().json;
const scenes = data.scenes || [];
const topicId = data.topic_id;
const projectId = data.project_id;

const sbUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;
const falKey = $env.FAL_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Exponential backoff helper
async function fetchWithRetry(url, options, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return res;
      const errText = await res.text();
      lastErr = new Error(`HTTP ${res.status}: ${errText.slice(0, 300)}`);
      if (res.status === 429) {
        await sleep(30000 * attempt);
        continue;
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) {
      lastErr = e;
    }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  throw lastErr || new Error('fetchWithRetry: all attempts failed');
}

// Claude motion prompt rewriter
async function rewriteToMotionPrompt(imagePrompt) {
  const systemMsg = `You are a video motion prompt expert. Rewrite the given static image prompt into a motion-enhanced prompt suitable for AI image-to-video generation (Seedance 2.0). Add subtle, cinematic motion descriptions: camera movements (slow dolly, gentle pan, slight push-in), environmental motion (wind, particles, light shifts, smoke, water ripple), and character micro-movements (breathing, blinking, subtle gestures). Keep it under 200 words. Maintain the original subject and composition. Output ONLY the rewritten prompt text, no explanation.`;

  const res = await fetchWithRetry('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': anthropicKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 400,
      system: systemMsg,
      messages: [{ role: 'user', content: `Rewrite this static image prompt for video motion:\n\n${imagePrompt}` }]
    })
  });

  const body = await res.json();
  return (body.content && body.content[0] && body.content[0].text) || imagePrompt;
}

// Fal.ai Seedance 2.0 Fast I2V — async queue pattern
async function generateI2V(imageUrl, motionPrompt) {
  // Submit to queue
  const submitRes = await fetchWithRetry('https://queue.fal.run/fal-ai/seedance-2.0-fast/image-to-video', {
    method: 'POST',
    headers: {
      'Authorization': `Key ${falKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      image_url: imageUrl,
      prompt: motionPrompt,
      duration: '10',
      aspect_ratio: '16:9'
    })
  });

  const submitBody = await submitRes.json();
  const requestId = submitBody.request_id;
  if (!requestId) throw new Error('Fal.ai did not return request_id: ' + JSON.stringify(submitBody).slice(0, 300));

  // Poll for completion
  const statusUrl = `https://queue.fal.run/fal-ai/seedance-2.0-fast/requests/${requestId}/status`;
  const resultUrl = `https://queue.fal.run/fal-ai/seedance-2.0-fast/requests/${requestId}`;
  const maxPolls = 120; // 10 min max (5s intervals)

  for (let poll = 0; poll < maxPolls; poll++) {
    await sleep(5000);
    try {
      const statusRes = await fetch(statusUrl, {
        headers: { 'Authorization': `Key ${falKey}` }
      });
      const statusBody = await statusRes.json();

      if (statusBody.status === 'COMPLETED') {
        // Fetch result
        const resultRes = await fetch(resultUrl, {
          headers: { 'Authorization': `Key ${falKey}` }
        });
        const resultBody = await resultRes.json();
        const videoUrl = resultBody.video && resultBody.video.url;
        if (!videoUrl) throw new Error('No video URL in Fal.ai result: ' + JSON.stringify(resultBody).slice(0, 300));
        return { videoUrl, requestId, durationMs: 10000 };
      }

      if (statusBody.status === 'FAILED') {
        throw new Error('Fal.ai Seedance generation FAILED: ' + JSON.stringify(statusBody).slice(0, 300));
      }
      // IN_QUEUE or IN_PROGRESS — continue polling
    } catch (e) {
      if (poll === maxPolls - 1) throw e;
      // Transient error — continue polling
    }
  }
  throw new Error(`Fal.ai Seedance timed out after ${maxPolls * 5}s for request ${requestId}`);
}

