    const i2vResult = await generateI2V(scene.image_url, motionPrompt);

    // 3. Calculate cost: Seedance 2.0 Fast ~$0.25 per clip + Haiku ~$0.001
    const sceneCost = 0.25;
    totalCost += sceneCost;

    // 4. PATCH scene in Supabase
    const patchBody = {
      video_clip_url: i2vResult.videoUrl,
      video_clip_duration_ms: i2vResult.durationMs,
      video_status: 'uploaded'
    };

    await fetch(`${sbUrl}/rest/v1/scenes?id=eq.${scene.id}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(patchBody)
    });

    // 5. Log success
    await fetch(`${sbUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: topicId,
        stage: 'i2v_hybrid',
        scene_number: scene.scene_number,
        action: 'seedance_i2v',
        status: 'success',
        duration_ms: Date.now() - sceneStart,
        cost_usd: sceneCost,
        retry_count: 0
      })
    });

    completed++;
    results.push({ scene_id: scene.id, scene_number: scene.scene_number, status: 'uploaded', videoUrl: i2vResult.videoUrl });

    // Rate limit: wait 15s between Seedance submissions
    if (scenes.indexOf(scene) < scenes.length - 1) {
      await sleep(15000);
    }
  } catch (err) {
    failed++;
    // Mark scene as failed
    try {
      await fetch(`${sbUrl}/rest/v1/scenes?id=eq.${scene.id}`, {
        method: 'PATCH',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({ video_status: 'failed' })
      });
    } catch (_) { }

    // Log failure
    try {
      await fetch(`${sbUrl}/rest/v1/production_logs`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: projectId,
          topic_id: topicId,
          stage: 'i2v_hybrid',
          scene_number: scene.scene_number,
          action: 'seedance_i2v',
          status: 'failed',
          duration_ms: Date.now() - sceneStart,
          cost_usd: 0,
          retry_count: 0
        })
      });
    } catch (_) { }

    results.push({ scene_id: scene.id, scene_number: scene.scene_number, status: 'failed', error: err.message });
  }
}

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  total_video_scenes: scenes.length,
  completed,
  failed,
  total_cost: totalCost,
  results
} }];

