      stage: 'i2v_hybrid',
      scene_number: null,
      action: 'completed',
      status: 'success',
      duration_ms: 0,
      cost_usd: data.total_cost || 0,
      retry_count: 0
    })
  });
} catch (_) { }

// Fire Ken Burns webhook to continue pipeline
try {
  await fetch('http://localhost:5678/webhook/production/ken-burns', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${$env.DASHBOARD_API_TOKEN}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ topic_id: topicId, project_id: projectId })
  });
} catch (_) { }

return [{ json: {
  success: true,
  topic_id: topicId,
  project_id: projectId,
  completed: data.completed || 0,
  failed: data.failed || 0,
  total_cost: data.total_cost || 0,
  next_stage: 'ken_burns',
  message: `I2V hybrid complete: ${data.completed || 0} uploaded, ${data.failed || 0} failed. Advancing to Ken Burns.`
} }];

// No video scenes to process — pipeline already advanced to ken_burns in Fetch node
const data = $input.first().json;
return [{ json: { success: true, topic_id: data.topic_id, project_id: data.project_id, message: data.message || 'No video scenes — skipped I2V, advanced to ken_burns', skipped: true } }];
